1	const BASE_PREMIUM = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	} as const;
8	
9	export type ItemType = keyof typeof BASE_PREMIUM;
10	
11	export type Item = { type: ItemType };
12	
13	const BLOCK_SIZE = 3;
14	const BLOCK_PREMIUM = 60;
15	const COMPONENT_TYPES: ReadonlySet<ItemType> = new Set<ItemType>(["rune"]);
16	
17	function isComponentBlock(items: Item[]): boolean {
18	  return (
19	    items.length === BLOCK_SIZE &&
20	    COMPONENT_TYPES.has(items[0].type) &&
21	    items.every((item) => item.type === items[0].type)
22	  );
23	}
24	
25	export function calculateBasePremium(items: Item[]): number {
26	  if (isComponentBlock(items)) {
27	    return BLOCK_PREMIUM;
28	  }
29	  return items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
30	}
